option.value:
/* ========================================
   PyCharm Markdown Preview
   AI Research / Knowledge Base Style
   ======================================== */

body {
    width: 100%;
    max-width: 1000px;

    margin: 0 auto;
    padding: 24px 32px;

    background: #1e1f22;
    color: #d4d4d4;

    font-family:
        -apple-system,
        BlinkMacSystemFont,
        "Segoe UI",
        "PingFang SC",
        "Microsoft YaHei",
        sans-serif;

    font-size: 16px;
    line-height: 1.9;
}

/* ========================================
   Heading
   ======================================== */

h1 {
    font-size: 2.4em;
    font-weight: 700;

    text-align: center;

    color: #ffffff;

    margin-top: 0.5em;
    margin-bottom: 1.6em;

    padding-bottom: 0.5em;

    border-bottom: 1px solid #333840;
}

h2 {
    font-size: 1.6em;
    font-weight: 700;

    color: #ffffff;

    margin-top: 2.5em;
    margin-bottom: 1em;

    padding-left: 14px;

    border-left: 5px solid #a855f7;
}

h3 {
    font-size: 1.15em;
    font-weight: 700;

    color: #f0e7ff;

    margin-top: 2em;
    margin-bottom: 1em;

    padding: 10px 14px;

    border-left: 4px solid #a855f7;

    background: linear-gradient(
        90deg,
        rgba(168,85,247,.18),
        rgba(168,85,247,0)
    );

    border-radius: 6px;
}

h4 {
    font-size: 1.05em;
    color: #d8b4fe;
}

/* ========================================
   Paragraph
   ======================================== */

p {
    margin: 1em 0;
}

/* ========================================
   Strong / Em
   ======================================== */

strong {
    color: #e879f9;
    font-weight: 700;

    background: rgba(232,121,249,.08);

    padding: 1px 4px;
    border-radius: 4px;
}

em {
    color: #c4b5fd;
}

/* ========================================
   List
   ======================================== */

ul,
ol {
    padding-left: 1.8em;
}

li {
    margin: 0.5em 0;
}

li::marker {
    color: #a855f7;
}

/* ========================================
   Blockquote
   ======================================== */

blockquote {
    margin: 1.5em 0;
    padding: 12px 18px;

    background: #282a30;

    border-left: 4px solid #a855f7;

    color: #d1d5db;

    border-radius: 6px;
}

/* ========================================
   Divider
   ======================================== */

hr {
    border: none;
    border-top: 1px solid #333840;

    margin: 2.5em 0;
}

/* ========================================
   Inline Code
   ======================================== */

code {
    font-family:
        "JetBrains Mono",
        Consolas,
        monospace;

    background: #2b2d33;

    color: #facc15;

    padding: 2px 6px;

    border-radius: 4px;

    font-size: 0.92em;
}

/* ========================================
   Code Block
   ======================================== */

pre {
    background: #15171b;

    border: 1px solid #333840;

    border-radius: 10px;

    padding: 18px 20px;

    overflow-x: auto;

    margin: 1.5em 0;
}

pre code {
    background: transparent;
    color: #e5e7eb;
    padding: 0;
}

/* ========================================
   Link
   ======================================== */

a {
    color: #a78bfa;
    text-decoration: none;
}

a:hover {
    color: #d8b4fe;
}

/* ========================================
   Table
   ======================================== */

table {
    width: 100%;
    border-collapse: collapse;
    margin: 1.5em 0;
}

th,
td {
    border: 1px solid #3a3f48;
    padding: 10px 12px;
}

th {
    background: #2b2d33;
    color: #ffffff;
}

tr:nth-child(even) {
    background: #25272d;
}

/* ========================================
   Image
   ======================================== */

img {
    max-width: 100%;
    border-radius: 8px;
    margin: 1em 0;
}

/* ========================================
   Selection
   ======================================== */

::selection {
    background: #7c3aed;
    color: white;
}
